export const CAT_W = 98;
export const CAT_H = 107;

const SPRITE_B64 = "";

export function decodeSpriteRGBA(): Uint8Array {
  const bin = atob(SPRITE_B64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

const REGION_B64 = "";

export function decodeRegionMap(): Uint8Array {
  const bin = atob(REGION_B64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

